  return(
    <div>
  <Title isRed = {false}>
    Login  <br/>
    <small>Em breve</small>
  </Title>
  <p>
    Estamos trabalhando para trazer essa funcionalidade o mais rápido possivel.
  </p>
  </div>
  )
}
